package us.dot.its.jpo.geojsonconverter.converter.rtcm;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.junit.Test;
import us.dot.its.jpo.asn.j2735.r2024.Common.RTCMmessageList;

import java.util.List;

import static org.hamcrest.MatcherAssert.assertThat;
import static org.hamcrest.Matchers.*;
import static us.dot.its.jpo.geojsonconverter.converter.rtcm.RTCMDecoder.unsigned;

public class RTCMDecoderTest {

    private final static ObjectMapper mapper = new ObjectMapper();

    @Test
    public void testSplitMessages_SingleCombined() throws JsonProcessingException, RTCMDecodeException {
        testSplitMessages(MESSAGE_LIST_J3258_SINGLE);
    }

    @Test
    public void testSplitMessages_Fragmented() throws JsonProcessingException, RTCMDecodeException {
        testSplitMessages(MESSAGE_LIST_J3258_FRAGMENTED);
    }

    @Test
    public void testSplitMessages_V1MessagesShouldWork() throws JsonProcessingException, RTCMDecodeException {
        // Not the normal case, but this code should still work to combine and split messages.
        testSplitMessages(MESSAGE_LIST_CTI4501_V1);
    }


    private void testSplitMessages(String messageListJson) throws JsonProcessingException, RTCMDecodeException {
        RTCMmessageList messageList = mapper.readValue(messageListJson, RTCMmessageList.class);
        RTCMDecoder decoder = new RTCMDecoder(false);
        List<byte[]> splitMessages = decoder.splitMessages(messageList);
        assertThat(splitMessages, hasSize(greaterThan(0)));
        for (byte[] splitMessage : splitMessages) {
            int preamble = unsigned(splitMessage[0]);
            assertThat(preamble, equalTo(0xD3));
        }
    }


    // CTI-4501 V1: 1 message per RTCMmessage.
    private final static String MESSAGE_LIST_CTI4501_V1 = """
        [
            "D300133ED980037BDD1A80C6358121DD4E499FFC6712E91F0D",
            "D3003E409980144144564E554C4C414E54454E4E4120204E4F4E4500000D5452494D424C4520414C4C4F59144E617620352E3434202F20426F6F7420352E3434008C65F9"
        ]
        """;

    // Several RTCM messages concatenated in one J2735 RTCMmessage, as is allowed in J3258.
    private final static String MESSAGE_LIST_J3258_SINGLE = """
        [
            ""
        ]
        """;

    // RTCMmessages plit up at byte boundaries, but not at RTCM message boundaries, as is allowed in J3258,
    // with maximum possible number of messages (5) allowed in J2735.
    private final static String MESSAGE_LIST_J3258_FRAGMENTED = """
        [
            "D300153EE00103012E3ADE9E350FDE024F89F13209210000393065D300DA43200175A4B302002084012D060000000020210100777FFFF7A223A622A528A229B0CD89FB6831753E7D27E61DCC07988CFD19FC23FC229E85638AD817B82BC05938B3917EFC",
            "C5399AF347E8C07810F759F084047A07B406682CFA57F9DFF547EE0F4CE33D79CFF5E74846D201324FC4C94005C87C1977F065E081F84B0817E8281A90A06A82BE56FA5FDBEC675FB19D3F06230F23083EF3A0FBCFC42E82F46F57D1F6FF47DBFFAB42FF",
            "73C3FDCF0FFB84FFFFFFFFFFFFFFFFFFFBBBBFFFFFFC0000001A69AE38614C93D98E5B7375D9692454DB9E7A4B25170071F5D9D300EC44600175A4B30000209185052000000000200111007FFFFFFFACAAA8A72D2DAC28FF92E67FCF01D0C42BC9ED46DC",
            "ADBAC3789617CC5218B5319914D12A425588ADF005201DE04FC0CB8BB81A6036086ED6862D385A86353F175630906248C78621EC4B78A7717D7B848BF08177C306FF140A792DCDE99A7FA8543EA96C85CF5C1A9EF86E8521B9F580711A02ECF00D5B2039",
            "C88275820A18E82804E0A9827987A9E6355F98A8FE6DC585C47217E46062A3018A04791363E69A8F9D111E7A0D7FFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF80000000577616DD8E9867AF1AEBBF5BD55E175155D5D96E1663A6F98044DBA6"
        ]
        """;
}
